+/// Block configuration for building MobileNet-V3.
+#[derive(Clone, Debug)]
+struct BlockConfig {
+    /// Input channels
+    in_channels: usize,
+    /// Expanded channels (after 1x1 expansion)
+    expanded_channels: usize,
+    /// Output channels
+    out_channels: usize,
+    /// Kernel size for depthwise conv
+    kernel_size: usize,
+    /// Stride for depthwise conv
+    stride: usize,
+    /// Whether to use Squeeze-and-Excitation
+    use_se: bool,
+    /// Activation type (ReLU or HardSwish)
+    activation: ActivationType,
+}
+
+impl BlockConfig {
+    fn new(
+        in_c: usize,
+        exp_c: usize,
+        out_c: usize,
+        kernel: usize,
+        stride: usize,
+        use_se: bool,
+        activation: ActivationType,
+    ) -> Self {
+        Self {
+            in_channels: in_c,
+            expanded_channels: exp_c,
+            out_channels: out_c,
+            kernel_size: kernel,
+            stride,
+            use_se,
+            activation,
+        }
+    }
+}
