+            BlockConfig::new(80, 200, 80, 3, 1, false, ActivationType::HardSwish),
+            BlockConfig::new(80, 184, 80, 3, 1, false, ActivationType::HardSwish),
+            BlockConfig::new(80, 184, 80, 3, 1, false, ActivationType::HardSwish),
+            BlockConfig::new(80, 480, 112, 3, 1, true, ActivationType::HardSwish),
