+/// Compute cosine similarity with precomputed norms.
+#[inline]
+fn cosine_similarity_normalized(a: &[f64], b: &[f64], norm_a: f64, norm_b: f64) -> f64 {
+    let dot: f64 = a.iter().zip(b.iter()).map(|(x, y)| x * y).sum();
+    dot / (norm_a * norm_b)
+}
