+/// Numerically stable log-sum-exp for two values.
+#[inline]
+fn log_sum_exp_pair(a: f64, b: f64) -> f64 {
+    if a == f64::NEG_INFINITY {
+        b
+    } else if b == f64::NEG_INFINITY {
+        a
+    } else if a > b {
+        a + (1.0 + (b - a).exp()).ln()
+    } else {
+        b + (1.0 + (a - b).exp()).ln()
+    }
+}
