+    }
+
+    /// Get the output shape for a given input shape
+    pub fn output_shape(&self, input_shape: &[usize]) -> CnnResult<Vec<usize>> {
+        if input_shape.len() != 4 {
+            return Err(CnnError::invalid_shape(
