+                                sum0 = _mm256_add_ps(sum0, _mm256_mul_ps(input_val, kernel_v));
+                            }
+                        }
+                    }
+                }
+
+                // Combine accumulators
+                let sum01 = _mm256_add_ps(sum0, sum1);
+                let sum23 = _mm256_add_ps(sum2, sum3);
+                let sum = _mm256_add_ps(sum01, sum23);
