+            // Remainder output channels
+            for oc in (out_c_chunks * 8)..out_c {
+                let mut sum = 0.0f32;
+                for kh in 0..3 {
+                    for kw in 0..3 {
+                        let ih = (oh * stride + kh) as isize - padding as isize;
+                        let iw = (ow * stride + kw) as isize - padding as isize;
