+    // Handle remainder channels
+    let inv_spatial_scalar = 1.0 / spatial as f32;
+    for ch in (c_chunks * 8)..c {
+        let mut sum = 0.0f32;
+        for s in 0..spatial {
+            sum += input[s * c + ch];
+        }
+        output[ch] = sum * inv_spatial_scalar;
+    }
+}
