+
+        for batch in images.chunks(batch_size) {
+            // Generate augmented pairs
+            let pairs: Vec<_> = batch
+                .iter()
+                .flat_map(|img| {
+                    let (v1, v2) = augmentation.generate_pair(img);
+                    vec![v1, v2]
+                })
+                .collect();
+
+            // Forward pass
+            let embeddings = model.forward_batch(&pairs)?;
+
+            // Compute loss
+            let loss = loss_fn.forward(&embeddings);
+            epoch_loss += loss;
+
